# GraphQL Types

class Dimensions(graphene.ObjectType):
    length = graphene.Float(description="Length in centimeters")
    width = graphene.Float(description="Width in centimeters")
    height = graphene.Float(description="Height in centimeters")


class ReviewUser(graphene.ObjectType):
    """User who wrote a review"""
    id = graphene.ID(required=True)
    username = graphene.String(required=True)
    display_name = graphene.String(required=True)


class Review(graphene.ObjectType):
    """A user review for a product"""
    id = graphene.ID(required=True)
    product_id = graphene.ID(required=True)
    user = graphene.Field(ReviewUser, description="The user who wrote this review")
    rating = graphene.Int(required=True, description="Rating from 1 to 5")
    title = graphene.String(required=True)
    comment = graphene.String()
    is_verified_purchase = graphene.Boolean(description="Whether the reviewer actually purchased the product")
    helpful_count = graphene.Int(description="Number of users who found this review helpful")
    created_at = graphene.DateTime()
    updated_at = graphene.DateTime()
    product = graphene.Field(lambda: Product, description="The product being reviewed")

    def resolve_user(self, info):
        review_data = next((r for r in REVIEWS if r["id"] == self.id), None)
        if review_data:
            user_data = next((u for u in USERS if u["id"] == review_data["user_id"]), None)
            if user_data:
                return ReviewUser(
                    id=user_data["id"],
                    username=user_data["username"],
                    display_name=user_data["display_name"],
                )
        return None

    def resolve_product(self, info):
        product_data = next((p for p in PRODUCTS if p["id"] == self.product_id), None)
        if product_data:
            return _build_product(product_data)
        return None


class ProductPriceRange(graphene.ObjectType):
    """Price range for filtering"""
    min_price = graphene.Float()
    max_price = graphene.Float()


class Category(graphene.ObjectType):
    """A product category in the catalog"""
    id = graphene.ID(required=True)
    name = graphene.String(required=True)
    description = graphene.String()
    parent = graphene.Field(lambda: Category, description="Parent category, if this is a subcategory")
    subcategories = graphene.List(lambda: Category, description="Child categories")
    products = graphene.List(
        lambda: Product,
        include_inactive=graphene.Boolean(default_value=False, description="Include inactive/out-of-stock products"),
        description="Products in this category",
    )
    product_count = graphene.Int(description="Number of active products in this category")

    def resolve_parent(self, info):
        cat_data = next((c for c in CATEGORIES if c["id"] == self.id), None)
        if cat_data and cat_data["parent_id"]:
            parent_data = next((c for c in CATEGORIES if c["id"] == cat_data["parent_id"]), None)
            if parent_data:
                return _build_category(parent_data)
        return None

    def resolve_subcategories(self, info):
        subcats = [c for c in CATEGORIES if c["parent_id"] == self.id]
        return [_build_category(c) for c in subcats]

    def resolve_products(self, info, include_inactive=False):
        prods = [p for p in PRODUCTS if p["category_id"] == self.id]
        if not include_inactive:
            prods = [p for p in prods if p["is_active"]]
        return [_build_product(p) for p in prods]

    def resolve_product_count(self, info):
        return len([p for p in PRODUCTS if p["category_id"] == self.id and p["is_active"]])


class ReviewSummary(graphene.ObjectType):
    """Aggregated review statistics for a product"""
    average_rating = graphene.Float()
    total_reviews = graphene.Int()
    rating_distribution = graphene.List(graphene.Int, description="Count of reviews for each rating 1-5")


class Product(graphene.ObjectType):
    """A product in the catalog"""
    id = graphene.ID(required=True)
    name = graphene.String(required=True)
    description = graphene.String()
    price = graphene.Float(required=True)
    currency = graphene.String()
    sku = graphene.String(required=True, description="Stock Keeping Unit identifier")
    stock_quantity = graphene.Int()
    in_stock = graphene.Boolean(description="Whether the product is currently in stock")
    category = graphene.Field(Category, description="The category this product belongs to")
    brand = graphene.String()
    is_active = graphene.Boolean(description="Whether the product is currently active/available")
    tags = graphene.List(graphene.String)
    weight = graphene.Float(description="Weight in kilograms")
    dimensions = graphene.Field(Dimensions)
    images = graphene.List(graphene.String, description="URLs of product images")
    created_at = graphene.DateTime()
    updated_at = graphene.DateTime()
    reviews = graphene.List(
        Review,
        rating=graphene.Int(description="Filter reviews by exact rating"),
        verified_only=graphene.Boolean(default_value=False, description="Only show verified purchase reviews"),
        limit=graphene.Int(default_value=10, description="Maximum number of reviews to return"),
        offset=graphene.Int(default_value=0, description="Number of reviews to skip"),
        description="User reviews for this product",
    )
    review_summary = graphene.Field(ReviewSummary, description="Aggregated review statistics")

    def resolve_in_stock(self, info):
        return self.stock_quantity is not None and self.stock_quantity > 0

    def resolve_category(self, info):
        product_data = next((p for p in PRODUCTS if p["id"] == self.id), None)
        if product_data:
            cat_data = next((c for c in CATEGORIES if c["id"] == product_data["category_id"]), None)
            if cat_data:
                return _build_category(cat_data)
        return None

    def resolve_reviews(self, info, rating=None, verified_only=False, limit=10, offset=0):
        product_reviews = [r for r in REVIEWS if r["product_id"] == self.id]

        if rating is not None:
            product_reviews = [r for r in product_reviews if r["rating"] == rating]

        if verified_only:
            product_reviews = [r for r in product_reviews if r["is_verified_purchase"]]

        product_reviews = sorted(product_reviews, key=lambda r: r["created_at"], reverse=True)
        product_reviews = product_reviews[offset:offset + limit]

        return [_build_review(r) for r in product_reviews]

    def resolve_review_summary(self, info):
        product_reviews = [r for r in REVIEWS if r["product_id"] == self.id]
        total = len(product_reviews)
        if total == 0:
            return ReviewSummary(average_rating=0.0, total_reviews=0, rating_distribution=[0, 0, 0, 0, 0])

        avg = sum(r["rating"] for r in product_reviews) / total
        distribution = [0, 0, 0, 0, 0]
        for r in product_reviews:
            distribution[r["rating"] - 1] += 1

        return ReviewSummary(
            average_rating=round(avg, 2),
            total_reviews=total,
            rating_distribution=distribution,
        )


# Helper functions to build GraphQL objects from data dicts

def _build_category(data):
    return Category(
        id=data["id"],
        name=data["name"],
        description=data["description"],
    )


def _build_product(data):
    dims = data.get("dimensions")
    dimensions = None
    if dims:
        dimensions = Dimensions(
            length=dims.get("length"),
            width=dims.get("width"),
            height=dims.get("height"),
        )

    return Product(
        id=data["id"],
        name=data["name"],
        description=data["description"],
        price=data["price"],
        currency=data["currency"],
        sku=data["sku"],
        stock_quantity=data["stock_quantity"],
        brand=data["brand"],
        is_active=data["is_active"],
        tags=data.get("tags", []),
        weight=data.get("weight"),
        dimensions=dimensions,
        images=data.get("images", []),
        created_at=datetime.fromisoformat(data["created_at"]) if data.get("created_at") else None,
        updated_at=datetime.fromisoformat(data["updated_at"]) if data.get("updated_at") else None,
    )


def _build_review(data):
    return Review(
        id=data["id"],
        product_id=data["product_id"],
        rating=data["rating"],
        title=data["title"],
        comment=data.get("comment"),
        is_verified_purchase=data.get("is_verified_purchase", False),
        helpful_count=data.get("helpful_count", 0),
        created_at=datetime.fromisoformat(data["created_at"]) if data.get("created_at") else None,
        updated_at=datetime.fromisoformat(data["updated_at"]) if data.get("updated_at") else None,
    )


# Sort enums

class ProductSortField(graphene.Enum):
    NAME = "name"
    PRICE = "price"
    CREATED_AT = "created_at"
    RATING = "rating"


class SortOrder(graphene.Enum):
    ASC = "asc"
    DESC = "desc"


# Connection / Pagination types

class ProductConnection(graphene.ObjectType):
    """Paginated list of products"""
    items = graphene.List(Product, required=True)
    total_count = graphene.Int(required=True, description="Total number of matching products")
    has_next_page = graphene.Boolean(required=True)
    has_previous_page = graphene.Boolean(required=True)


class ReviewConnection(graphene.ObjectType):
    """Paginated list of reviews"""
    items = graphene.List(Review, required=True)
    total_count = graphene.Int(required=True)
    has_next_page = graphene.Boolean(required=True)
    has_previous_page = graphene.Boolean(required=True)


# Mutations

class AddReview(graphene.Mutation):
    class Arguments:
        product_id = graphene.ID(required=True)
        user_id = graphene.ID(required=True)
        rating = graphene.Int(required=True)
        title = graphene.String(required=True)
        comment = graphene.String()
        is_verified_purchase = graphene.Boolean(default_value=False)

    ok = graphene.Boolean()
    review = graphene.Field(Review)
    error = graphene.String()

    def mutate(self, info, product_id, user_id, rating, title, comment=None, is_verified_purchase=False):
        # Validate product exists
        product = next((p for p in PRODUCTS if p["id"] == product_id), None)
        if not product:
            return AddReview(ok=False, review=None, error=f"Product with id '{product_id}' not found")

        # Validate user exists
        user = next((u for u in USERS if u["id"] == user_id), None)
        if not user:
            return AddReview(ok=False, review=None, error=f"User with id '{user_id}' not found")

        # Validate rating
        if rating < 1 or rating > 5:
            return AddReview(ok=False, review=None, error="Rating must be between 1 and 5")

        now = datetime.utcnow().isoformat()
        new_id = str(max(int(r["id"]) for r in REVIEWS) + 1)

        new_review_data = {
            "id": new_id,
            "product_id": product_id,
            "user_id": user_id,
            "rating": rating,
            "title": title,
            "comment": comment,
            "is_verified_purchase": is_verified_purchase,
            "helpful_count": 0,
            "created_at": now,
            "updated_at": now,
        }
        REVIEWS.append(new_review_data)

        return AddReview(ok=True, review=_build_review(new_review_data), error=None)


class MarkReviewHelpful(graphene.Mutation):
    class Arguments:
        review_id = graphene.ID(required=True)

    ok = graphene.Boolean()
    review = graphene.Field(Review)
    error = graphene.String()

    def mutate(self, info, review_id):
        review_data = next((r for r in REVIEWS if r["id"] == review_id), None)
        if not review_data:
            return MarkReviewHelpful(ok=False, review=None, error=f"Review with id '{review_id}' not found")

        review_data["helpful_count"] = review_data.get("helpful_count", 0) + 1
        return MarkReviewHelpful(ok=True, review=_build_review(review_data), error=None)


class Mutation(graphene.ObjectType):
    add_review = AddReview.Field(description="Add a new review to a product")
    mark_review_helpful = MarkReviewHelpful.Field(description="Mark a review as helpful (increment helpful count)")


# Query

class Query(graphene.ObjectType):
    # Single item queries
    product = graphene.Field(
        Product,
        id=graphene.ID(description="Product ID"),
        sku=graphene.String(description="Product SKU"),
        description="Fetch a single product by ID or SKU",
    )
    category = graphene.Field(
        Category,
        id=graphene.ID(required=True),
        description="Fetch a single category by ID",
    )
    review = graphene.Field(
        Review,
        id=graphene.ID(required=True),
        description="Fetch a single review by ID",
    )

    # List queries
    products = graphene.Field(
        ProductConnection,
        search=graphene.String(description="Search products by name, description, or tags"),
        category_id=graphene.ID(description="Filter by category ID"),
        brand=graphene.String(description="Filter by brand name"),
        min_price=graphene.Float(description="Minimum price filter"),
        max_price=graphene.Float(description="Maximum price filter"),
        in_stock_only=graphene.Boolean(default_value=False, description="Only show in-stock products"),
        include_inactive=graphene.Boolean(default_value=False, description="Include inactive products"),
        sort_by=ProductSortField(default_value=ProductSortField.CREATED_AT),
        sort_order=SortOrder(default_value=SortOrder.DESC),
        limit=graphene.Int(default_value=20, description="Maximum number of products to return"),
        offset=graphene.Int(default_value=0, description="Number of products to skip"),
        description="Search and filter products with pagination",
    )

    categories = graphene.List(
        Category,
        top_level_only=graphene.Boolean(default_value=False, description="Only return top-level categories"),
        description="List all categories",
    )

    reviews = graphene.Field(
        ReviewConnection,
        product_id=graphene.ID(description="Filter by product ID"),
        user_id=graphene.ID(description="Filter by user ID"),
        min_rating=graphene.Int(description="Minimum rating filter"),
        max_rating=graphene.Int(description="Maximum rating filter"),
        verified_only=graphene.Boolean(default_value=False),
        limit=graphene.Int(default_value=20),
        offset=graphene.Int(default_value=0),
        description="Search and filter reviews with pagination",
    )

    # Utility queries
    brands = graphene.List(graphene.String, description="List all available brands")
    price_range = graphene.Field(
        ProductPriceRange,
        category_id=graphene.ID(description="Optional category filter"),
        description="Get the price range of all active products",
    )

    # Resolvers

    def resolve_product(self, info, id=None, sku=None):
        if id:
            data = next((p for p in PRODUCTS if p["id"] == id), None)
        elif sku:
            data = next((p for p in PRODUCTS if p["sku"] == sku), None)
        else:
            return None
        if data:
            return _build_product(data)
        return None

    def resolve_category(self, info, id):
        data = next((c for c in CATEGORIES if c["id"] == id), None)
        if data:
            return _build_category(data)
        return None

    def resolve_review(self, info, id):
        data = next((r for r in REVIEWS if r["id"] == id), None)
        if data:
            return _build_review(data)
        return None

    def resolve_products(
        self, info,
        search=None, category_id=None, brand=None,
        min_price=None, max_price=None,
        in_stock_only=False, include_inactive=False,
        sort_by=ProductSortField.CREATED_AT, sort_order=SortOrder.DESC,
        limit=20, offset=0,
    ):
        filtered = list(PRODUCTS)

        # Filter inactive
        if not include_inactive:
            filtered = [p for p in filtered if p["is_active"]]

        # Search
        if search:
            search_lower = search.lower()
            filtered = [
                p for p in filtered
                if search_lower in p["name"].lower()
                or search_lower in p.get("description", "").lower()
                or any(search_lower in tag.lower() for tag in p.get("tags", []))
            ]

        # Category filter (include subcategories)
        if category_id:
            category_ids = {category_id}
            # Find all subcategory ids recursively
            def find_subcategory_ids(parent_id):
                for c in CATEGORIES:
                    if c["parent_id"] == parent_id:
                        category_ids.add(c["id"])
                        find_subcategory_ids(c["id"])
            find_subcategory_ids(category_id)
            filtered = [p for p in filtered if p["category_id"] in category_ids]

        # Brand filter
        if brand:
            filtered = [p for p in filtered if p.get("brand", "").lower() == brand.lower()]

        # Price filters
        if min_price is not None:
            filtered = [p for p in filtered if p["price"] >= min_price]
        if max_price is not None:
            filtered = [p for p in filtered if p["price"] <= max_price]

        # In stock filter
        if in_stock_only:
            filtered = [p for p in filtered if p.get("stock_quantity", 0) > 0]

        # Sorting
        sort_field_value = sort_by if isinstance(sort_by, str) else sort_by.value
        reverse = (sort_order if isinstance(sort_order, str) else sort_order.value) == "desc"

        if sort_field_value == "rating":
            def get_avg_rating(product):
                product_reviews = [r for r in REVIEWS if r["product_id"] == product["id"]]
                if not product_reviews:
                    return 0.0
                return sum(r["rating"] for r in product_reviews) / len(product_reviews)
            filtered.sort(key=get_avg_rating, reverse=reverse)
        else:
            filtered.sort(key=lambda p: p.get(sort_field_value, ""), reverse=reverse)

        total_count = len(filtered)
        paginated = filtered[offset:offset + limit]

        return ProductConnection(
            items=[_build_product(p) for p in paginated],
            total_count=total_count,
            has_next_page=(offset + limit) < total_count,
            has_previous_page=offset > 0,
        )

    def resolve_categories(self, info, top_level_only=False):
        if top_level_only:
            cats = [c for c in CATEGORIES if c["parent_id"] is None]
        else:
            cats = CATEGORIES
        return [_build_category(c) for c in cats]

    def resolve_reviews(
        self, info,
        product_id=None, user_id=None,
        min_rating=None, max_rating=None,
        verified_only=False,
        limit=20, offset=0,
    ):
        filtered = list(REVIEWS)

        if product_id:
            filtered = [r for r in filtered if r["product_id"] == product_id]
        if user_id:
            filtered = [r for r in filtered if r["user_id"] == user_id]
        if min_rating is not None:
            filtered = [r for r in filtered if r["rating"] >= min_rating]
        if max_rating is not None:
            filtered = [r for r in filtered if r["rating"] <= max_rating]
        if verified_only:
            filtered = [r for r in filtered if r["is_verified_purchase"]]

        filtered.sort(key=lambda r: r["created_at"], reverse=True)
        total_count = len(filtered)
        paginated = filtered[offset:offset + limit]

        return ReviewConnection(
            items=[_build_review(r) for r in paginated],
            total_count=total_count,
            has_next_page=(offset + limit) < total_count,
            has_previous_page=offset > 0,
        )

    def resolve_brands(self, info):
        brands = sorted(set(p["brand"] for p in PRODUCTS if p.get("brand") and p["is_active"]))
        return brands

    def resolve_price_range(self, info, category_id=None):
        filtered = [p for p in PRODUCTS if p["is_active"]]
        if category_id:
            category_ids = {category_id}
            def find_subcategory_ids(parent_id):
                for c in CATEGORIES:
                    if c["parent_id"] == parent_id:
                        category_ids.add(c["id"])
                        find_subcategory_ids(c["id"])
            find_subcategory_ids(category_id)
            filtered = [p for p in filtered if p["category_id"] in category_ids]

        if not filtered:
            return ProductPriceRange(min_price=0.0, max_price=0.0)

        prices = [p["price"] for p in filtered]
        return ProductPriceRange(min_price=min(prices), max_price=max(prices))


