app.add_url_rule(
    "/graphql",
    view_func=GraphQLView.as_view(
        "graphql",
        schema=schema,
        graphiql=True,  # Enable GraphiQL interactive explorer for development
    ),
)


@app.route("/")
def index():
    return {
        "service": "E-Commerce Product Catalog API",
        "version": "1.0.0",
        "graphql_endpoint": "/graphql",
        "graphiql": "/graphql",
        "description": "GraphQL API for browsing products, categories, and reviews. Visit /graphql for the interactive explorer.",
    }


@app.route("/health")
def health():
    return {
        "status": "healthy",
        "products_count": len(PRODUCTS),
        "categories_count": len(CATEGORIES),
        "reviews_count": len(REVIEWS),
    }


